/// <summary>
/// Contract class for the process of generating quota contract lines for the ETGSPAIN model.
/// </summary>
[DataContract,
SysOperationContractProcessing(classStr(ETGSPAINPurchSalesAgreementQuotaDialogUIBuilder)),
SysOperationGroup('Parameters', "@ETGSPAINLabels:Parameters", '1'),
SysOperationGroup('Dates', "@ETGSPAINLabels:ETGSPAINAgreementQuotasDates", '2')
]
class ETGSPAINPurchSalesAgreementQuotaDialogContract implements SysOperationValidatable
{
    RefRecId                          agreementHeaderRecId;
    ETGSPAINPurchAgreementQuotaPeriods     ETGSPAINPurchAgreementQuotaPeriods;
    ETGSPAINPurchAgreementQuotaFromDate    ETGSPAINPurchAgreementQuotaFromDate;
    ETGSPAINPurchAgreementQuotaToDate      ETGSPAINPurchAgreementQuotaToDate;

}

Method.Source:
/// <summary>
/// Parameter for agreement header record identifier.
/// </summary>
/// <param name = "_agreementHeaderRecId">RefRecId</param>
/// <returns>Record identifier of the agreement header.</returns>
[DataMember,
 SysOperationControlVisibility(false)]
public RefRecId parmAgreementHeaderRecId(RefRecId _agreementHeaderRecId = agreementHeaderRecId)
{
    agreementHeaderRecId = _agreementHeaderRecId;

    return agreementHeaderRecId;
}

/// <summary>
/// Parameter for the number of periods.
/// </summary>
/// <param name = "_ETGSPAINPurchAgreementQuotaPeriods">ETGSPAINPurchAgreementQuotaPeriods</param>
/// <returns>Number of periods.</returns>
[DataMember,        
SysOperationDisplayOrder('1'),
SysOperationGroupMember('Parameters')
]
public ETGSPAINPurchAgreementQuotaPeriods parmQuotaPeriods(ETGSPAINPurchAgreementQuotaPeriods _ETGSPAINPurchAgreementQuotaPeriods = ETGSPAINPurchAgreementQuotaPeriods)
{
    ETGSPAINPurchAgreementQuotaPeriods = _ETGSPAINPurchAgreementQuotaPeriods;

    return ETGSPAINPurchAgreementQuotaPeriods;
}

/// <summary>
/// Parameter for the start date of the quota.
/// </summary>
/// <param name = "_ETGSPAINPurchAgreementQuotaFromDate">ETGSPAINPurchAgreementQuotaFromDate</param>
/// <returns>Start date of the quota.</returns>
[DataMember,
SysOperationDisplayOrder('1'),
SysOperationGroupMember('Dates')
]
public ETGSPAINPurchAgreementQuotaFromDate parmQuotaFromDate(ETGSPAINPurchAgreementQuotaFromDate _ETGSPAINPurchAgreementQuotaFromDate = ETGSPAINPurchAgreementQuotaFromDate)
{
    ETGSPAINPurchAgreementQuotaFromDate = _ETGSPAINPurchAgreementQuotaFromDate;

    return ETGSPAINPurchAgreementQuotaFromDate;
}

/// <summary>
/// Parameter for the end date of the quota.
/// </summary>
/// <param name = "_ETGSPAINPurchAgreementQuotaToDate">ETGSPAINPurchAgreementQuotaToDate</param>
/// <returns>End date of the quota.</returns>
[DataMember,
SysOperationDisplayOrder('2'),
SysOperationGroupMember('Dates')
]
public ETGSPAINPurchAgreementQuotaToDate parmQuotaToDate(ETGSPAINPurchAgreementQuotaToDate _ETGSPAINPurchAgreementQuotaToDate = ETGSPAINPurchAgreementQuotaToDate)
{
    ETGSPAINPurchAgreementQuotaToDate = _ETGSPAINPurchAgreementQuotaToDate;

    return ETGSPAINPurchAgreementQuotaToDate;
}

/// <summary>
/// Validates if the contract parameters are valid.
/// </summary>
/// <returns>Returns true if the parameters are valid, otherwise false.</returns>
public boolean validate()
{
    boolean isValid = true;

    if (AgreementHeader::find(agreementHeaderRecId).ETGSPAINPurchHasAgreementQuotas)
    {
        return true;
    }

    if (ETGSPAINPurchAgreementQuotaPeriods <= 0)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:FieldMustBeFilled", "@ETGSPAINLabels:ETGSPAINPurchAgreementQuotaPeriods"));
    }

    if (!ETGSPAINPurchAgreementQuotaFromDate)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:FieldMustBeFilled", "@ETGSPAINLabels:ETGSPAINPurchAgreementQuotaFromDate"));
    }

    if (ETGSPAINPurchAgreementQuotaFromDate && dayOfMth(ETGSPAINPurchAgreementQuotaFromDate) != 1)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:DateMustBeFirstDayOfMonth", "@ETGSPAINLabels:ETGSPAINPurchAgreementQuotaFromDate"));
    }

    if (!ETGSPAINPurchAgreementQuotaToDate)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:FieldMustBeFilled", "@ETGSPAINLabels:ETGSPAINPurchAgreementQuotaToDate"));
    }

    if (ETGSPAINPurchAgreementQuotaToDate && ETGSPAINPurchAgreementQuotaToDate != endMth(ETGSPAINPurchAgreementQuotaToDate))
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:DateMustBeLastDayOfMonth", "@ETGSPAINLabels:ETGSPAINPurchAgreementQuotaToDate"));
    }

    if (ETGSPAINPurchAgreementQuotaFromDate > ETGSPAINPurchAgreementQuotaToDate)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:QuotaPeriodValidationError", date2StrUsr(ETGSPAINPurchAgreementQuotaFromDate, DateFlags::FormatAll), date2StrUsr(ETGSPAINPurchAgreementQuotaToDate, DateFlags::FormatAll)));
    }

    return isValid;
}
